(1, 'Refund & Cancellation Policy', '返金＆キャンセルポリシー', 'refund-policy', '<section class=\"section-terms padding-tb-50\">\n  <div class=\"container\">\n    <div class=\"row\">\n      <div class=\"col-12\">\n        <div class=\"section-title bb-center\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"200\">\n          <div class=\"section-detail\">\n            <!-- <h2 class=\"bb-title\">Refund & <span>Cancellation Policy</span></h2> -->\n          </div>\n        </div>\n      </div>\n\n      <div class=\"desc\">\n        <div class=\"row mb-minus-24\">\n          <div class=\"col-lg-12 col-md-12 mb-24\">\n            <div class=\"terms-detail\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"400\">\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <p>We’re committed to delivering top-notch courses and support. This policy explains the conditions under which refunds and cancellations may be granted.</p>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <p>We value your satisfaction. If you face any technical issues or are not fully happy with the service, we recommend reaching out to our support team first so we can try to resolve the issue.</p>\n                <p><strong>You may be eligible for a refund if:</strong></p>\n                <ul style=\"margin-left: 20px;\">\n                  <li style=\"margin-bottom: 10px;\">A request is submitted within 14 days of purchase along with a valid reason.</li>\n                  <li style=\"margin-bottom: 10px;\">The transaction was unauthorized or fraudulent, with proof provided.</li>\n                  <li style=\"margin-bottom: 10px;\">Technical difficulties prevent access to the course and cannot be resolved within a reasonable timeframe.</li>\n                  <li style=\"margin-bottom: 10px;\">Other exceptional circumstances apply, as assessed on a case-by-case basis.</li>\n                </ul>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <h3>Refund Misuse</h3>\n                <ul style=\"margin-left: 20px;\">\n                  <li style=\"margin-bottom: 10px;\">Repeated refund requests without valid cause may result in restrictions on future purchases.</li>\n                  <li style=\"margin-bottom: 10px;\">Breaching the Terms of Service may result in loss of refund eligibility.</li>\n                </ul>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <h3>Cancellation Policy</h3>\n                <p>To request a cancellation, simply send an email to <a href=\"mailto: Info@learn-withus.com\"> Info@learn-withus.com</a> with your order ID and the reason for cancellation. Each case will be reviewed individually.</p>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <h3>Important Notes</h3>\n                <ul style=\"margin-left: 20px;\">\n                  <li style=\"margin-bottom: 10px;\">This policy forms part of the broader Terms of Service. By making a purchase, you confirm your acceptance of these terms.</li>\n                  <li style=\"margin-bottom: 10px;\">All prior transactions made before account closure remain subject to this policy.</li>\n                </ul>\n              </div>\n\n              <div class=\"block\">\n                <p>Still have questions? Contact our support team anytime at <a href=\"mailto: Info@learn-withus.com\"> Info@learn-withus.com</a> – we’re here to help!</p>\n              </div>\n\n            </div>\n          </div>\n        </div>\n      </div>\n\n    </div>\n  </div>\n</section>\n', '<section class=\"section-terms padding-tb-50\">\n  <div class=\"container\">\n    <div class=\"row\">\n      <div class=\"col-12\">\n        <div class=\"section-title bb-center\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"200\">\n          <div class=\"section-detail\">\n            ; <h2 class=\"bb-title\">返金および<span>キャンセルポリシー</span></h2>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"desc\">\n        <div class=\"row mb-minus-24\">\n          <div class=\"col-lg-12 col-md-12 mb-24\">\n            <div class=\"terms-detail\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"400\">\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <p>当社は、質の高いコースとサポートを提供することに尽力しています。このポリシーでは、返金およびキャンセルが認められる条件について説明しています。</p>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <p>お客様の満足が最優先です。技術的な問題が発生した場合やサービスにご満足いただけなかった場合は、まずサポートチームまでご連絡いただければ、問題の解決に努めます。</p>\n                <p><strong>以下の場合、返金の対象となる可能性があります：</strong></p>\n                <ul style=\"margin-left: 20px;\">\n                  <li style=\"margin-bottom: 10px;\">購入日から14日以内に、正当な理由を添えてリクエストを提出した場合。</li>\n                  <li style=\"margin-bottom: 10px;\">不正または詐欺的な取引であることが証明された場合。</li>\n                  <li style=\"margin-bottom: 10px;\">技術的な問題によりコースにアクセスできず、合理的な期間内に解決できない場合。</li>\n                  <li style=\"margin-bottom: 10px;\">その他、個別に判断される特別な事情がある場合。</li>\n                </ul>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <h3>返金の不正利用</h3>\n                <ul style=\"margin-left: 20px;\">\n                  <li style=\"margin-bottom: 10px;\">正当な理由のない返金リクエストを繰り返すと、今後の購入に制限がかかる可能性があります。</li>\n                  <li style=\"margin-bottom: 10px;\">利用規約に違反した場合、返金の権利を失うことがあります。</li>\n                </ul>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <h3>キャンセルポリシー</h3>\n                <p>キャンセルをご希望の場合は、注文IDとキャンセルの理由を明記のうえ、<a href=\"mailto:Info@learn-withus.com\">Info@learn-withus.com</a> までメールでご連絡ください。各ケースは個別に審査されます。</p>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <h3>重要事項</h3>\n                <ul style=\"margin-left: 20px;\">\n                  <li style=\"margin-bottom: 10px;\">このポリシーは、当社の利用規約の一部です。購入することで、これらの条件に同意したものとみなされます。</li>\n                  <li style=\"margin-bottom: 10px;\">アカウントを閉鎖する前に行われたすべての取引は、本ポリシーの対象となります。</li>\n                </ul>\n              </div>\n\n              <div class=\"block\">\n                <p>ご不明な点がございましたら、いつでもサポートチームまでご連絡ください。<a href=\"mailto:Info@learn-withus.com\">Info@learn-withus.com</a> – 喜んでサポートいたします！</p>\n              </div>\n\n            </div>\n          </div>\n        </div>\n      </div>\n\n    </div>\n  </div>\n</section>\n', NULL, NULL),
(2, 'Privacy Policy', '個人情報保護方針', 'privacy-policy', '<section class=\"section-terms padding-tb-50\">\n  <div class=\"container\">\n    <div class=\"row\">\n      <div class=\"col-12\">\n        <div class=\"section-title bb-center\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"200\">\n          <div class=\"section-detail\">\n            <h2 class=\"bb-title\">Privacy <span>Policy</span></h2>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"desc\">\n        <div class=\"row mb-minus-24\">\n          <div class=\"col-lg-12 col-md-12 mb-24\">\n            <div class=\"terms-detail\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"400\">\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <p>We are committed to protecting your privacy and safeguarding any personal information shared while using this website. This Privacy Policy explains what data may be collected during your visit and how that information may be used.</p>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <h3>1. Collection and Use of Personal Information</h3>\n                <p>You\'re welcome to browse the website without submitting any personal data. However, to access certain services, some personal information may be required.</p>\n                <p>We only collect personally identifiable information in the following cases:</p>\n                <ul style=\"margin-left: 20px;\">\n                  <li style=\"margin-bottom: 10px;\">When you voluntarily provide it through website forms (e.g., course sign-up, contact forms).</li>\n                  <li style=\"margin-bottom: 10px;\">When it\'s gathered through standard usage statistics during your visit.</li>\n                </ul>\n                <p>Any personal data provided is handled with the highest care and will only be used for the purposes you consent to. Your information is never sold, rented, or shared with third parties—unless required by legal authorities via court orders, subpoenas, or similar legal processes, or when necessary to protect or enforce legal rights.</p>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <h3>2. Collection and Use of Non-Personal Information</h3>\n                <p>To better understand how our website is used and improve user experience, we automatically collect certain non-personal data such as:</p>\n                <ul style=\"margin-left: 20px;\">\n                  <li style=\"margin-bottom: 10px;\">IP address</li>\n                  <li style=\"margin-bottom: 10px;\">Browser type</li>\n                  <li style=\"margin-bottom: 10px;\">Domain name</li>\n                  <li style=\"margin-bottom: 10px;\">Date and time of access</li>\n                  <li style=\"margin-bottom: 10px;\">Referring URLs</li>\n                </ul>\n                <p>This information is used for analytics and system optimization. In some cases, third-party providers may be engaged to help analyze this data. These third parties are required to maintain strict confidentiality and use appropriate data security measures.</p>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <h3>3. Cookies</h3>\n                <p>We use cookies—small text files stored on your device—to personalize your experience and gather website usage data. Cookies help recognize repeat visitors and tailor content accordingly.</p>\n                <p>Cookies do not provide access to your computer or any personal data beyond what you choose to share.</p>\n                <p>Most browsers accept cookies by default, but you can modify your browser settings to decline them if you prefer. Please note that disabling cookies may limit your experience on the website.</p>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <h3>4. External Links</h3>\n                <p>This website may contain links to other websites of interest. Please be aware that once you leave our site, we do not have control over those external sites. This Privacy Policy does not apply to them, so it’s recommended to review the privacy practices of any third-party websites you visit.</p>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <h3>5. Data Security</h3>\n                <p>We take your data protection seriously and apply appropriate technical and organizational measures to secure your information. However, no website can guarantee complete security. We are not responsible for data breaches, service interruptions, or unauthorized access beyond our control.</p>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <h3>6. Policy Updates</h3>\n                <p>This Privacy Policy may be updated periodically. Any changes will be posted on this page, and your continued use of the website implies acceptance of those changes. This policy does not constitute a legal contract or create enforceable rights.</p>\n              </div>\n\n              <div class=\"block\">\n                <p>For any questions or privacy-related requests, feel free to reach out to our support team. We aim to respond within 5 business days.</p>\n              </div>\n\n            </div>\n          </div>\n        </div>\n      </div>\n\n    </div>\n  </div>\n</section>\n', '<section class=\"section-terms padding-tb-50\">\n  <div class=\"container\">\n    <div class=\"row\">\n      <div class=\"col-12\">\n        <div class=\"section-title bb-center\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"200\">\n          <div class=\"section-detail\">\n            ; <h2 class=\"bb-title\">プライバシー <span>ポリシー</span></h2>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"desc\">\n        <div class=\"row mb-minus-24\">\n          <div class=\"col-lg-12 col-md-12 mb-24\">\n            <div class=\"terms-detail\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"400\">\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <p>当サイトでは、お客様のプライバシーを尊重し、提供された個人情報の保護に努めています。本プライバシーポリシーでは、ご利用中に収集される可能性のある情報と、その利用方法について説明します。</p>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <h3>1. 個人情報の収集と利用</h3>\n                <p>個人情報を提供しなくても、当サイトをご利用いただけます。ただし、一部のサービスをご利用いただくには、個人情報の提供が必要な場合があります。</p>\n                <p>当社が個人を特定できる情報を収集するのは、以下の場合に限られます：</p>\n                <ul style=\"margin-left: 20px;\">\n                  <li style=\"margin-bottom: 10px;\">サイトのフォーム（例：コース申し込み、問い合わせフォーム）を通じて自発的に提供された場合</li>\n                  <li style=\"margin-bottom: 10px;\">サイト利用時に収集される標準的なアクセス情報</li>\n                </ul>\n                <p>提供された個人情報は、同意された目的のみに使用し、慎重に取り扱います。法律上の義務（例：裁判所命令、召喚状など）または法的権利の保護が必要な場合を除き、第三者に販売、賃貸、共有されることはありません。</p>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <h3>2. 非個人情報の収集と利用</h3>\n                <p>ユーザー体験の向上およびサイトの利用状況を把握するため、以下のような非個人情報を自動的に収集する場合があります：</p>\n                <ul style=\"margin-left: 20px;\">\n                  <li style=\"margin-bottom: 10px;\">IPアドレス</li>\n                  <li style=\"margin-bottom: 10px;\">ブラウザの種類</li>\n                  <li style=\"margin-bottom: 10px;\">ドメイン名</li>\n                  <li style=\"margin-bottom: 10px;\">アクセス日時</li>\n                  <li style=\"margin-bottom: 10px;\">参照元URL</li>\n                </ul>\n                <p>これらの情報は、分析およびシステムの最適化のために使用されます。必要に応じて、外部業者にデータ分析を委託することがありますが、彼らは厳格な機密保持義務と適切なセキュリティ対策を講じる必要があります。</p>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <h3>3. クッキーの使用</h3>\n                <p>当サイトでは、クッキー（お客様の端末に保存される小さなテキストファイル）を使用し、利用体験のパーソナライズおよび使用状況データの収集を行っています。</p>\n                <p>クッキーにより、再訪問者を識別し、適切なコンテンツを表示できますが、ユーザーのコンピューターや個人情報にアクセスすることはありません。</p>\n                <p>ほとんどのブラウザはデフォルトでクッキーを受け入れますが、設定で無効にすることも可能です。ただし、無効にした場合、一部の機能が制限される場合があります。</p>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <h3>4. 外部リンク</h3>\n                <p>当サイトには、他のウェブサイトへのリンクが含まれている場合があります。外部サイトにアクセスされた場合、そのサイトのプライバシーポリシーは当社のものとは異なり、当社は責任を負いません。訪問先のサイトのプライバシーポリシーをご確認ください。</p>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <h3>5. データの安全性</h3>\n                <p>当社は、提供された情報を保護するために、適切な技術的・組織的対策を講じています。ただし、どのウェブサイトも完全なセキュリティを保証することはできません。予期しないデータ漏洩や第三者による不正アクセスに関して、当社では責任を負いかねます。</p>\n              </div>\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <h3>6. ポリシーの変更</h3>\n                <p>本プライバシーポリシーは、必要に応じて更新されることがあります。変更内容はこのページに掲載され、サイトを継続してご利用いただくことで、それらの変更に同意したものとみなされます。本ポリシーは、法的な契約や強制力のある権利を構成するものではありません。</p>\n              </div>\n\n              <div class=\"block\">\n                <p>ご質問やプライバシーに関するご要望がございましたら、サポートチームまでご連絡ください。通常、5営業日以内にご返信いたします。</p>\n              </div>\n\n            </div>\n          </div>\n        </div>\n      </div>\n\n    </div>\n  </div>\n</section>\n', NULL, NULL),
(3, 'Delivery Policy', '配送ポリシー', 'delivery-policy', '<section class=\"section-terms padding-tb-50\">\n  <div class=\"container\">\n    <div class=\"row\">\n      <div class=\"col-12\">\n        <div class=\"section-title bb-center\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"200\">\n          <!-- <div class=\"section-detail\">\n            <h2 class=\"bb-title\">Delivery <span>Policy</span></h2>\n          </div> -->\n        </div>\n      </div>\n\n      <div class=\"desc\">\n        <div class=\"row mb-minus-24\">\n          <div class=\"col-lg-12 col-md-12 mb-24\">\n            <div class=\"terms-detail\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"400\">\n\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <p>We are committed to providing prompt and hassle-free access to your digital learning materials. This policy outlines how course content is delivered after a successful purchase.</p>\n\n                <h4>Course Access & Delivery Process</h4>\n                <p><strong>Email Confirmation:</strong> Once payment is confirmed, course access details and digital materials will be sent to the email address provided at checkout.</p>\n                <p><strong>Timing:</strong> Emails are typically delivered within a few minutes. However, in some cases, it may take up to 24 hours due to system delays.</p>\n                <p><strong>Access Period:</strong> Courses will remain accessible for 2 weeks from the date the email is sent. After this window, access will automatically expire.</p>\n\n                <h4>What to Do If You Don’t Receive the Email</h4>\n                <ul style=\"margin-left: 20px;\">\n                  <li style=\"margin-bottom: 10px;\">Check your spam or junk folder.</li>\n                  <li style=\"margin-bottom: 10px;\">Verify that your email address was entered correctly at checkout.</li>\n                  <li style=\"margin-bottom: 10px;\">Still need help? Contact our support team at <a href=\"mailto:Info@learn-withus.com\">Info@learn-withus.com</a> and we’ll assist you promptly.</li>\n                </ul>\n\n                <h4>Important Reminders</h4>\n                <ul style=\"margin-left: 20px;\">\n                  <li style=\"margin-bottom: 10px;\">All courses are delivered digitally only—there’s no physical shipping involved.</li>\n                  <li style=\"margin-bottom: 10px;\">It’s your responsibility to access or download course materials within the 2-week access window.</li>\n                  <li style=\"margin-bottom: 10px;\">Course content is for personal use only and must not be shared, resold, or distributed without written permission.</li>\n                </ul>\n\n                <p>For any questions or delivery issues, feel free to reach out to us at <a href=\"mailto:Info@learn-withus.com\">Info@learn-withus.com</a>. We\'re here to help!</p>\n              </div>\n\n            </div>\n          </div>\n        </div>\n      </div>\n\n    </div>\n  </div>\n</section>\n', '<section class=\"section-terms padding-tb-50\">\n  <div class=\"container\">\n    <div class=\"row\">\n      <div class=\"col-12\">\n        <div class=\"section-title bb-center\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"200\">\n          <div class=\"section-detail\">\n           \n          </div>\n        </div>\n      </div>\n\n      <div class=\"desc\">\n        <div class=\"row mb-minus-24\">\n          <div class=\"col-lg-12 col-md-12 mb-24\">\n            <div class=\"terms-detail\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"400\">\n\n              <div class=\"block\" style=\"margin-bottom: 40px;\">\n                <p>お客様に迅速かつスムーズにデジタル学習教材をご提供することをお約束します。本ポリシーでは、購入完了後の教材配信方法について説明しています。</p>\n\n                <h4>コースアクセスと配信プロセス</h4>\n                <p><strong>メール確認：</strong> お支払いが確認されると、チェックアウト時にご入力いただいたメールアドレス宛にコース情報と教材が送信されます。</p>\n                <p><strong>配信時間：</strong> 通常、数分以内にメールが届きますが、システムの都合により最大24時間かかる場合があります。</p>\n                <p><strong>アクセス期間：</strong> メール送信日から2週間の間、コースにアクセス可能です。その後、自動的にアクセスは無効になります。</p>\n\n                <h4>メールが届かない場合の対応</h4>\n                <ul style=\"margin-left: 20px;\">\n                  <li style=\"margin-bottom: 10px;\">迷惑メールフォルダやスパムフォルダをご確認ください。</li>\n                  <li style=\"margin-bottom: 10px;\">チェックアウト時に入力されたメールアドレスが正しいかご確認ください。</li>\n                  <li style=\"margin-bottom: 10px;\">それでも届かない場合は、<a href=\"mailto:Info@learn-withus.com\">Info@learn-withus.com</a> までご連絡ください。すぐに対応いたします。</li>\n                </ul>\n\n                <h4>重要なご注意事項</h4>\n                <ul style=\"margin-left: 20px;\">\n                  <li style=\"margin-bottom: 10px;\">すべてのコースはデジタル配信のみで、物理的な配送はありません。</li>\n                  <li style=\"margin-bottom: 10px;\">2週間のアクセス期間中に、教材にアクセスまたはダウンロードする責任はお客様にあります。</li>\n                  <li style=\"margin-bottom: 10px;\">教材は個人利用のみであり、許可なく共有・再販売・配布することはできません。</li>\n                </ul>\n\n                <p>ご質問や配信に関する問題がある場合は、<a href=\"mailto:Info@learn-withus.com\">Info@learn-withus.com</a> までお気軽にお問い合わせください。いつでもサポートいたします！</p>\n              </div>\n\n            </div>\n          </div>\n        </div>\n      </div>\n\n    </div>\n  </div>\n</section>\n', NULL, NULL),
(4, 'Terms & Conditions', 'ご利用規約', 'terms-conditions', '<section class=\"section-terms padding-tb-50\">\n  <div class=\"container\">\n    <div class=\"row\">\n      <div class=\"col-12\">\n        <div class=\"section-title bb-center\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"200\">\n          <div class=\"section-detail\">\n            <!-- <h2 class=\"bb-title\">Terms & <span>Conditions</span></h2> -->\n          </div>\n        </div>\n      </div>\n\n      <div class=\"desc\">\n        <div class=\"row mb-minus-24\">\n          <div class=\"col-lg-12 col-md-12 mb-24\">\n            <div class=\"terms-detail\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"400\">\n              <div class=\"terms-info-contact\">\n              <p><strong>Company Name</strong> Learn Withus</p>\n              <p><strong>Email</strong> Info@learn-withus.com</p>\n              <p><strong>Address</strong> UNIT 1812, 18/F., CHINAWEAL CENTRE,<br>\n                414-424 JAFFE ROAD,CAUSEWAY BAY, HONG KONG</p>\n              <p><strong>DBA</strong>&nbsp; <img src=\"../assets/images/dba.png\" width=\"82px\" height=\"13px\" alt=\"LearnWUS\" /></p>\n              </div>\n              <div class=\"block\">\n                <h3>1. Introduction</h3>\n                <p>Thank you for choosing our courses. These Terms and Conditions outline your rights and responsibilities when using our website and services.\n                  By purchasing and accessing our digital learning content, you agree to comply with these terms. If you do not agree, we kindly ask that you do not use our services</p>\n              </div>\n\n              <div class=\"block\">\n                <h3>2. Services</h3>\n                <p>We offer digital educational content accessible upon successful purchase.</p>\n                <p>Course materials will be delivered to the email address you provide during checkout.</p>\n                <p>Access to course content is available for a period of two weeks from the date of delivery.</p>\n                <p>We reserve the right to update, modify, pause, or discontinue any service with prior notice. Refunds may be provided at our sole discretion.</p>\n              </div>\n\n              <div class=\"block\">\n                <h3>3. Payments & Transactions</h3>\n                <p>All payments are processed securely through our trusted payment gateway.</p>\n                <p>We accept payments in Japanese Yen (JP¥) and U.S. Dollars (US$).</p>\n                <p>After your transaction is completed, you will receive an order ID by email for reference.</p>\n              </div>\n\n              <div class=\"block\">\n                <h3>4. Refund & Cancellation Policy</h3>\n                <p>Refund requests must be submitted within 14 days of purchase and are subject to our Refund Policy.</p>\n                <p>Cancellation requests are assessed individually and follow the terms outlined in our Cancellation Policy.</p>\n              </div>\n\n              <div class=\"block\">\n                <h3>5. Intellectual Property</h3>\n                <p>All course materials are protected intellectual property and are intended strictly for personal use only.</p>\n                <p>Redistribution, resale, reproduction, or modification of any course content is not permitted.</p>\n              </div>\n\n              <div class=\"block\">\n                <h3>6. Liability & Disclaimers</h3>\n                <p>All courses are provided “as is,” without any guarantees of uninterrupted access or freedom from technical errors.</p>\n                <p>We are not liable for indirect or consequential damages resulting from course usage.</p>\n              </div>\n\n              <div class=\"block\">\n                <h3>7. Privacy & Data Protection</h3>\n                <p>By submitting your information, you consent to us using your data for course delivery and support purposes.</p>\n                <p>We do not share your personal information with any third party unless legally required to do so.</p>\n              </div>\n\n              <div class=\"block\">\n                <h3>8. Confidentiality</h3>\n                <p>Any confidential information shared in the course environment will remain protected and will not be disclosed without your explicit permission.</p>\n              </div>\n\n              <div class=\"block\">\n                <h3>9. Governing Law & Jurisdiction</h3>\n                <p>These terms are governed by the laws of Hong Kong.</p>\n                <p>When you purchase the service from our website, your credit card bill will show the description as \"<img src=\"../assets/images/dba.png\" width=\"82px\" height=\"13px\" alt=\"LearnWUS\" />\".</p>\n                <p> All disputes will be subject to the exclusive jurisdiction of the courts in Hong Kong.</p>\n              </div>\n\n            </div>\n          </div>\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n', '<section class=\"section-terms padding-tb-50\">\n  <div class=\"container\">\n    <div class=\"row\">\n      <div class=\"col-12\">\n        <div class=\"section-title bb-center\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"200\">\n          <div class=\"section-detail\">\n           \n          </div>\n        </div>\n      </div>\n\n      <div class=\"desc\">\n        <div class=\"row mb-minus-24\">\n          <div class=\"col-lg-12 col-md-12 mb-24\">\n            <div class=\"terms-detail\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"400\">\n              <div class=\"terms-info-contact\">\n                <p><strong>会社名</strong>Learn Withus</p>\n                <p><strong>メールアドレス</strong> Info@learn-withus.com</p>\n               <p><strong>住所</strong> UNIT1812,18/F.LOCATION414-424JAFFE ROAD<br>\n                   ,銅鑼湾,香港</p>\n                <p><strong>DBA</strong>  <img src=\"../assets/images/dba.png\" width=\"82px\" height=\"13px\" alt=\"LearnWUS\" /></p>\n              </div>\n\n              <div class=\"block\">\n                <h3>1. はじめに</h3>\n                <p>当社のコースをお選びいただきありがとうございます。本利用規約では、当社のウェブサイトおよびサービスのご利用に際するお客様の権利と義務について定めています。<br>\n                  当社のデジタル学習コンテンツを購入・利用することで、本規約に同意したものとみなされます。ご同意いただけない場合は、当サービスのご利用をお控えください。</p>\n              </div>\n\n              <div class=\"block\">\n                <h3>2. サービス内容</h3>\n                <p>当社は、購入完了後にアクセス可能となるデジタル教育コンテンツを提供しています。</p>\n                <p>教材は、購入時にご入力いただいたメールアドレス宛に送信されます。</p>\n                <p>教材のアクセス期間は、配信日から2週間です。</p>\n                <p>当社は、事前通知の上でサービスの更新、変更、一時停止、または終了を行う権利を有します。返金の可否は当社の裁量によります。</p>\n              </div>\n\n              <div class=\"block\">\n                <h3>3. お支払いと取引</h3>\n                <p>すべてのお支払いは、信頼性の高い決済ゲートウェイを通じて安全に処理されます。</p>\n                <p>日本円（JP¥）および米ドル（US$）での支払いが可能です。</p>\n                <p>取引完了後、参照用として注文IDが記載されたメールが送信されます。</p>\n              </div>\n\n              <div class=\"block\">\n                <h3>4. 返金およびキャンセルポリシー</h3>\n                <p>返金のご依頼は、ご購入から14日以内に行ってください。内容は当社の返金ポリシーに準じます。</p>\n                <p>キャンセルのご依頼は個別に審査され、当社のキャンセルポリシーに基づいて処理されます。</p>\n              </div>\n\n              <div class=\"block\">\n                <h3>5. 知的財産権</h3>\n                <p>すべての教材は知的財産として保護されており、個人使用のみに限定されています。</p>\n                <p>コンテンツの再配布、再販、複製、改変は禁止されています。</p>\n              </div>\n\n              <div class=\"block\">\n                <h3>6. 免責事項と責任の制限</h3>\n                <p>すべてのコースは「現状のまま」提供されており、継続的なアクセスや技術的エラーがないことは保証されません。</p>\n                <p>コース利用によって発生した間接的または付随的損害について、当社は一切責任を負いません。</p>\n              </div>\n\n              <div class=\"block\">\n                <h3>7. プライバシーと個人情報の保護</h3>\n                <p>お客様の情報を送信することにより、当社がコース提供およびサポート目的でそのデータを使用することに同意したものとみなされます。</p>\n                <p>法的義務がある場合を除き、お客様の個人情報を第三者と共有することはありません。</p>\n              </div>\n\n              <div class=\"block\">\n                <h3>8. 機密保持</h3>\n                <p>コース内で共有された機密情報は保護され、お客様の明確な許可がない限り開示されることはありません。</p>\n              </div>\n\n              <div class=\"block\">\n                <h3>9. 準拠法および裁判管轄</h3>\n                <p>本規約は、香港の法律に準拠します。</p>\n                 <p>当社のウェブサイトからサービスを購入すると、クレジットカードの請求書には次のような説明が表示されます \"<img src=\"../assets/images/dba.png\" width=\"82px\" height=\"13px\" alt=\"LearnWUS\" />\".</p>\n                <p>すべての紛争は、香港の裁判所の専属管轄とします。</p>\n              </div>\n\n            </div>\n          </div>\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n', NULL, NULL);
INSERT INTO `pages` (`id`, `page_title`, `page_title_ja`, `page_slug`, `page_desc`, `page_desc_ja`, `page_meta`, `page_keywords`) VALUES
(5, 'About Us', '私達について', 'about-us', '\r\n      <!-- student-choose-area start -->\r\n      <div class=\"student-choose-area fix pt-110 pb-90\">\r\n         <div class=\"container\">\r\n            <div class=\"row\">\r\n               <div class=\"col-xl-7 col-lg-7\">\r\n                  <div class=\"student-wrapper mb-30\">\r\n                     <div class=\"section-title mb-30\">\r\n                        <h2>Why Learners <span class=\"down-mark-line\">Choose</span> Us to Build Skills That Make a Difference</h2>\r\n                     </div>\r\n                     <div class=\"sitdent-choose-content\">\r\n                        <p>Building skills and accelerating careers shouldn’t be an afterthought.\r\n                            In today’s competitive world, learners are looking for meaningful, flexible, and result-driven education—and that’s exactly what we deliver. With expert-designed content and learner-first tools, we’re helping thousands upgrade their future.\r\n                        </p>\r\n                     </div>\r\n                     <div class=\"student-choose-list\">\r\n                        <ul>\r\n                           <li><i class=\"far fa-check\"></i>Interactive Learning Experience</li>\r\n                           <p>Courses designed with real-life case studies, tools, and exercises for better understanding.</p>\r\n                           <li><i class=\"far fa-check\"></i>Simple & Seamless Enrollment</li>\r\n                           <p>Just a few clicks to get started. No complicated forms or waiting time.</p>\r\n                           <li><i class=\"far fa-check\"></i>Expert Instructors from Industry</li>\r\n                           <p>Our instructors are professionals with years of field experience—bringing real knowledge, not just theory.</p>\r\n                           <li><i class=\"far fa-check\"></i>Flexible Access</li>\r\n                           <p>Learn anytime, anywhere, on any device—your progress syncs automatically.</p>\r\n                        </ul>\r\n                     </div>\r\n                  </div>\r\n               </div>              \r\n      <div class=\"col-xl-5 col-lg-5\">\r\n        <div class=\"student-choose-wrapper position-relative mb-30\">\r\n                 <div class=\"about-img-wrap-10\">\r\n                            <div class=\"about-img-1\">\r\n<img src=\"assets/img/about-uimg.webp\" alt=\"about\"></div>\r\n                            <div class=\"about-img-2\"><img src=\"assets/img/about-uimage1.webp\" alt=\"about\"></div>\r\n                        </div>   \r\n                  </div>\r\n               </div>\r\n            </div>\r\n         </div>\r\n      </div>\r\n      <!-- student-choose-area end -->\r\n      <section class=\"section-story padding-tb-50\">\r\n         <div class=\"container\">\r\n           <div class=\"row\">\r\n             <div class=\"col-12\">\r\n               <div class=\"section-title bb-center\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"200\">\r\n                 <div class=\"section-detail\">\r\n                   <h2 class=\"bb-title\" style=\"text-align: center;\">How It All <span>Started</span></h2>\r\n                 </div>\r\n               </div>\r\n             </div>\r\n       \r\n             <div class=\"col-lg-10 offset-lg-1\">\r\n               <div class=\"story-detail\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"400\">\r\n                 \r\n                 <div class=\"block\">\r\n                   <h3>A Simple Idea</h3>\r\n                   <p>It began with a simple idea — what if learning could be more flexible, more accessible, and truly inspiring? A small group of educators, tech enthusiasts, and dreamers came together, all fueled by the same passion: to make quality education available to anyone, anywhere.</p>\r\n                 </div>\r\n       \r\n                 <div class=\"block\">\r\n                   <h3>A Passion Turned into Purpose</h3>\r\n                   <p>Frustrated by outdated systems and limited access, we saw an opportunity to do things differently. We weren’t just building a platform — we were creating a learning experience designed around real people, real goals, and real growth.</p>\r\n                 </div>\r\n       \r\n                 <div class=\"block\">\r\n                   <h3>Building Something Meaningful</h3>\r\n                   <p>Armed with industry experience and a desire to innovate, we set out to design practical, engaging courses across fields like business, tech, design, and personal development. Every course is built with purpose — by experts, for learners.</p>\r\n                 </div>\r\n       \r\n                 <div class=\"block\">\r\n                   <h3>Why We Do It</h3>\r\n                   <p>Our mission has always been simple: to empower individuals with the tools and confidence to grow. Whether it’s picking up a new skill, exploring a passion, or making a career move — we’re here to support every step of the journey.</p>\r\n                 </div>\r\n       \r\n                 <div class=\"block\">\r\n                   <h3>The Road Ahead</h3>\r\n                   <p>This is just the beginning. As we continue to grow, so does our commitment to delivering meaningful education that adapts to your needs. The future of learning is personal, and we’re excited to be part of yours.</p>\r\n                 </div>\r\n                 \r\n               </div>\r\n             </div>\r\n           </div>\r\n         </div>\r\n       </section>\r\n       \r\n      <!-- features-area-start -->\r\n      <div class=\"features-area section-bg fix pt-110\">\r\n         <div class=\"container\">\r\n            <div class=\"row\">\r\n               <div class=\"col-12\">\r\n                  <div class=\"section-title text-center mb-60\">\r\n                     <h2>Accelerate Your Growth <br>\r\n                        with <span class=\"down-mark-line-2\"> learn-withus.com </span></h2>\r\n                  </div>\r\n               </div>\r\n               <div class=\"col-xl-4 col-lg-4 col-md-6 col-sm-12\">\r\n                  <div class=\"features-box text-center mb-30\">\r\n                     <div class=\"features-svg\">\r\n                           <img src=\"assets/img/anime-1.png\" alt=\"feaut-img\"> \r\n                           \r\n                     </div>\r\n                     <div class=\"features-text\">\r\n                        <h4>Elevate Your Skills, Knowledge & Career</h4>\r\n                        <p>Whether you\'re upskilling, reskilling, or advancing your career, our courses are designed to help you grow with confidence and clarity.</p>\r\n                     </div>\r\n                  </div>\r\n               </div>\r\n               <div class=\"col-xl-4 col-lg-4 col-md-6 col-sm-12\">\r\n                  <div class=\"features-box text-center mb-30\">\r\n                     <div class=\"features-svg\">\r\n                               <img src=\"assets/img/anime-2.png\" alt=\"feaut-img\"> \r\n\r\n                                            </div>\r\n                     <div class=\"features-text\">\r\n                        <h4>Expert-Led Learning</h4>\r\n                        <p>Gain insights from industry leaders and seasoned professionals who bring real-world expertise to every lesson.</p>\r\n                     </div>\r\n                  </div>\r\n               </div>\r\n               <div class=\"col-xl-4 col-lg-4 col-md-6 col-sm-12\">\r\n                  <div class=\"features-box text-center mb-30\">\r\n                     <div class=\"features-svg\">\r\n                       <img src=\"assets/img/anime-3.png\" alt=\"feaut-img\"> \r\n                     </div>\r\n                     <div class=\"features-text\">\r\n                        <h4>Practical, Outcome-Driven Training</h4>\r\n                        <p>Our courses focus on actionable knowledge and skills that translate directly into career success and tangible results.</p>\r\n                     </div>\r\n                  </div>\r\n               </div>\r\n            </div>\r\n         </div>\r\n      </div>\r\n      <!-- features-area-end -->\r\n\r\n      <!-- counter-area start -->\r\n      <!-- <div class=\"counter-area pt-120 pb-75\">\r\n         <div class=\"container\">\r\n            <div class=\"row\">\r\n               <div class=\"col-xl-3 col-lg-3 col-md-6 col-sm-6\">\r\n                  <div class=\"counter-box text-center mb-40\">\r\n                     <div class=\"counter-icon\">\r\n                        <svg id=\"layer2\" xmlns=\"http://www.w3.org/2000/svg\" width=\"50.897\" height=\"56.553\"\r\n                           viewBox=\"0 0 50.897 56.553\">\r\n                           <path id=\"path3518\"\r\n                              d=\"M26.3.646,1.793,13.689a.834.834,0,0,0,.048,1.522L16.07,21.734h21.4L51.7,15.211a.834.834,0,0,0,.05-1.522L27.244.647a.9.9,0,0,0-.473-.117A1.023,1.023,0,0,0,26.3.646Z\"\r\n                              transform=\"translate(-1.323 -0.529)\" fill=\"#5299d3\" />\r\n                           <path id=\"path3534\"\r\n                              d=\"M16.66,2.911a35.363,35.363,0,0,0-7.55.718,9.782,9.782,0,0,0-2.456.841,3.065,3.065,0,0,0-.858.648,1.7,1.7,0,0,0-.451,1.106v7.4l-.077.893a17.977,17.977,0,0,1,22.781,0l-.077-.891v-7.4a1.7,1.7,0,0,0-.451-1.106,3.056,3.056,0,0,0-.856-.648,9.78,9.78,0,0,0-2.456-.841,35.363,35.363,0,0,0-7.55-.718Z\"\r\n                              transform=\"translate(8.788 5.574)\" fill=\"#a0c7e7\" />\r\n                           <path id=\"path3604\"\r\n                              d=\"M9.111,3.629a9.782,9.782,0,0,0-2.456.841,3.065,3.065,0,0,0-.858.648,1.7,1.7,0,0,0-.451,1.106v7.4l-.077.893a17.891,17.891,0,0,1,1.962-1.388V6.225a1.7,1.7,0,0,1,.451-1.106A3.066,3.066,0,0,1,8.54,4.47,9.782,9.782,0,0,1,11,3.629a34,34,0,0,1,6.607-.7c-.316-.006-.62-.02-.943-.02a35.36