954-4.031A8.919,8.919,0,0,0,4.468,38l40.581,0a4.03,4.03,0,1,1-.113,8.059Zm48.618,2.693a9,9,0,0,0,0,8.061l-40.467.007h0a4.034,4.034,0,0,1,0-8.068ZM28.273,35.3a4.029,4.029,0,1,1,.125-8.057H53.09a9,9,0,0,0,0,8.062Z\"\r\n                                 transform=\"translate(0 -2.461)\" />\r\n                              <path id=\"Path_7083\" data-name=\"Path 7083\"\r\n                                 d=\"M48.59,6.388,49.883,5.1V18.047a1.346,1.346,0,0,0,2.693,0V5.1l1.292,1.292a1.346,1.346,0,0,0,1.9-1.9L52.183.895a1.35,1.35,0,0,0-1.907,0L46.686,4.483a1.346,1.346,0,1,0,1.9,1.9Z\"\r\n                                 transform=\"translate(-4.686 0)\" />\r\n                              <path id=\"Path_7084\" data-name=\"Path 7084\"\r\n                                 d=\"M34.59,6.387,35.883,5.1V18.047a1.346,1.346,0,0,0,2.693,0V5.1l1.292,1.292a1.346,1.346,0,1,0,1.9-1.9L38.183.894a1.351,1.351,0,0,0-1.907,0L32.686,4.483a1.346,1.346,0,0,0,1.9,1.9Z\"\r\n                                 transform=\"translate(-3.254 0)\" />\r\n                           </g>\r\n                        </svg>\r\n                        <div class=\"count-number\">\r\n                           <span class=\"counter\">6,548</span>\r\n                           <p>Premium Courses</p>\r\n                        </div>\r\n                     </div>\r\n                  </div>\r\n               </div>\r\n            </div>\r\n         </div>\r\n      </div>\r\n       -->\r\n      <!-- become-intructor-area-start -->\r\n      <div class=\"become-intructor-area pt-110 pb-120\">\r\n         <div class=\"container\">\r\n            <div class=\"row justify-content-center text-center\">\r\n               <div class=\"col-xl-6 col-md-8\">\r\n                  <div class=\"become-intructor-text\">\r\n                     <h2>Learn from Industry-Leading Experts</h2>\r\n                     <p>Join one of the most dynamic online learning platforms, where expert instructors and dedicated support teams guide you every step of the way.</p>\r\n                     <a class=\"btn edu-btn\" href=\"/product-lists\">Start your journey today!</a>\r\n                  </div>\r\n               </div>\r\n            </div>\r\n         </div>\r\n      </div>\r\n      <!-- become-intructor-area-end -->', '\r\n      <!-- student-choose-area start -->\r\n      <div class=\"student-choose-area fix pt-110 pb-90\">\r\n         <div class=\"container\">\r\n            <div class=\"row\">\r\n               <div class=\"col-xl-7 col-lg-7\">\r\n                  <div class=\"student-wrapper mb-30\">\r\n                    <div class=\"section-title mb-30\">\r\n                      <h2>なぜ学習者は<span class=\"down-mark-line\">私たちを選ぶ</span>のか — 実践的なスキルを身につけるために</h2>\r\n                    </div>\r\n                    <div class=\"sitdent-choose-content\">\r\n                      <p>\r\n                        スキルの習得やキャリアの加速は、後回しにすべきではありません。<br>\r\n                        今日の競争社会において、学習者は意味のある、柔軟で結果に繋がる教育を求めています。それこそが、私たちが提供しているものです。<br>\r\n                        専門家によって設計されたコンテンツと学習者を第一に考えたツールで、数千人の未来のアップグレードを支援しています。\r\n                      </p>\r\n                    </div>\r\n                    <div class=\"student-choose-list\">\r\n                      <ul>\r\n                        <li><i class=\"far fa-check\"></i>インタラクティブな学習体験</li>\r\n                        <p>実際のケーススタディやツール、演習を取り入れ、理解を深めるために設計されたコース。</p>\r\n                \r\n                        <li><i class=\"far fa-check\"></i>簡単でスムーズな登録</li>\r\n                        <p>数回のクリックでスタートできます。面倒なフォーム入力や待ち時間はありません。</p>\r\n                \r\n                        <li><i class=\"far fa-check\"></i>業界の専門家による講義</li>\r\n                        <p>私たちの講師は、現場経験が豊富なプロフェッショナル。理論だけでなく、実際の知識をお届けします。</p>\r\n                \r\n                        <li><i class=\"far fa-check\"></i>柔軟なアクセス</li>\r\n                        <p>いつでも、どこでも、どのデバイスからでも学習可能。進捗は自動で同期されます。</p>\r\n                      </ul>\r\n                    </div>\r\n                  </div>\r\n                </div>\r\n                \r\n             \r\n               \r\n               <div class=\"col-xl-5 col-lg-5\">\r\n                 <div class=\"student-choose-wrapper position-relative mb-30\">\r\n                 <div class=\"about-img-wrap-10\">\r\n                            <div class=\"about-img-1\">\r\n<img src=\"assets/img/about-uimg.webp\" alt=\"about\"></div>\r\n                            <div class=\"about-img-2\"><img src=\"assets/img/about-uimage1.webp\" alt=\"about\"></div>\r\n                        </div>   \r\n                  </div>\r\n               </div>\r\n            </div>\r\n         </div>\r\n      </div>\r\n      <!-- student-choose-area end -->\r\n      <section class=\"section-story padding-tb-50\">\r\n         <div class=\"container\">\r\n           <div class=\"row\">\r\n             <div class=\"col-12\">\r\n               <div class=\"section-title bb-center\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"200\">\r\n                 <div class=\"section-detail\">\r\n                   <h2 class=\"bb-title\" style=\"text-align: center;\">どのようにそれすべて <span>開始</span></h2>\r\n                 </div>\r\n               </div>\r\n             </div>\r\n       \r\n             <div class=\"col-lg-10 offset-lg-1\">\r\n               <div class=\"story-detail\" data-aos=\"fade-up\" data-aos-duration=\"1000\" data-aos-delay=\"400\">\r\n                 \r\n               <div class=\"block\">\r\n  <h3>シンプルなアイデアから</h3>\r\n  <p>\r\n    学びがもっと柔軟で、もっとアクセスしやすく、心からインスピレーションを受けるものだったらどうだろう？<br>\r\n    そんなシンプルな発想からすべてが始まりました。教育者、テクノロジー愛好家、そして夢追い人が集い、共通の情熱を持って、誰にでも、どこにいても質の高い教育を届けることを目指しました。\r\n  </p>\r\n</div>\r\n\r\n               <div class=\"block\">\r\n               <h3>情熱が目的に変わった瞬間</h3>\r\n               <p>\r\n                  時代遅れの仕組みと限られたアクセスにフラストレーションを感じていた私たちは、「違うやり方」を追求することにしました。<br>\r\n                  単なるプラットフォームを作るのではなく、現実の人々、本物の目標、真の成長に基づいた学びの体験を創り上げようとしたのです。\r\n               </p>\r\n               </div>\r\n\r\n               <div class=\"block\">\r\n               <h3>意味のあるものをつくる</h3>\r\n               <p>\r\n                  業界での経験とイノベーションへの情熱を持って、私たちはビジネス、テクノロジー、デザイン、自己成長といった分野で、実践的かつ魅力的なコースを設計しました。<br>\r\n                  すべてのコースには目的があります —— 専門家が、学習者のために作ったのです。\r\n               </p>\r\n               </div>\r\n\r\n               <div class=\"block\">\r\n               <h3>私たちがそれをする理由</h3>\r\n               <p>\r\n                  私たちのミッションはとてもシンプルです：人々が成長するためのツールと自信を提供すること。<br>\r\n                  新しいスキルの習得でも、情熱の追求でも、キャリアの転機でも、あなたの旅路を全力でサポートします。\r\n               </p>\r\n               </div>\r\n\r\n               <div class=\"block\">\r\n               <h3>これからの道</h3>\r\n               <p>\r\n                  これは始まりにすぎません。<br>\r\n                  私たちが成長し続ける中で、あなたのニーズに応える有意義な教育を提供し続けるという決意もますます強くなっています。<br>\r\n                  学びの未来はパーソナルなもの。あなたの未来の一部になれることを、私たちは心から楽しみにしています。\r\n               </p>\r\n               </div>\r\n\r\n                 \r\n               </div>\r\n             </div>\r\n           </div>\r\n         </div>\r\n       </section>\r\n       \r\n      <!-- features-area-start -->\r\n      <div class=\"features-area section-bg fix pt-110\">\r\n         <div class=\"container\">\r\n            <div class=\"row\">\r\n               <div class=\"col-12\">\r\n                  <div class=\"section-title text-center mb-60\">\r\n                     <h2>あなたの成長を加速します。 <br>\r\n                        と <span class=\"down-mark-line-2\">Cloud-Bizinfo.com</span></h2>\r\n                  </div>\r\n               </div>\r\n               <div class=\"col-xl-4 col-lg-4 col-md-6 col-sm-12\">\r\n                  <div class=\"features-box text-center mb-30\">\r\n                      <div class=\"features-svg\">\r\n                           <img src=\"assets/img/anime-1.png\" alt=\"feaut-img\"> \r\n                           \r\n                     </div>\r\n                     <div class=\"features-text\">\r\n                        <h4>スキル、知識、キャリアを向上させる</h4>\r\n                        <p>あなたがスキルアップ、再スキル、またはあなたのキャリアを進めているかどうか、私たちのコースは、あなたが自信と明快さで成長するのに役立つよ</p>\r\n                     </div>\r\n                  </div>\r\n               </div>\r\n               <div class=\"col-xl-4 col-lg-4 col-md-6 col-sm-12\">\r\n                  <div class=\"features-box text-center mb-30\">\r\n                     <div class=\"features-svg\">\r\n                           <img src=\"assets/img/anime-2.png\" alt=\"feaut-img\"> \r\n                           \r\n                     </div>\r\n                     <div class=\"features-text\">\r\n                        <h4>専門家主導の学習</h4>\r\n                        <p>すべてのレッスンに現実世界の専門知識をもたらす業界のリーダーと経験豊富な専門家からの洞察を得る。</p>\r\n                     </div>\r\n                  </div>\r\n               </div>\r\n               <div class=\"col-xl-4 col-lg-4 col-md-6 col-sm-12\">\r\n                  <div class=\"features-box text-center mb-30\">\r\n                     <div class=\"features-svg\">\r\n                           <img src=\"assets/img/anime-3.png\" alt=\"feaut-img\"> \r\n                           \r\n                     </div>\r\n                     <div class=\"features-text\">\r\n                       <h4>実践的、成果主導型トレーニング</h4>\r\n                        <p>私たちのコースは、キャリアの成功と具体的な結果に直接変換実用的な知識とスキルに焦点を当てています。</p>\r\n                     </div>\r\n                  </div>\r\n               </div>\r\n            </div>\r\n         </div>\r\n      </div>\r\n      <!-- features-area-end -->\r\n      <!-- become-intructor-area-start -->\r\n      <div class=\"become-intructor-area pt-110 pb-120\">\r\n         <div class=\"container\">\r\n            <div class=\"row justify-content-center text-center\">\r\n               <div class=\"col-xl-6 col-md-8\">\r\n                  <div class=\"become-intructor-text\">\r\n                     <h2>業界をリードする専門家から学ぶ</h2>\r\n                     <p>最もダイナミックなオンライン学習プラットフォームの1つに参加してください。ここでは、専門家のインストラクターと専任のサポートチームがあらゆるステップをご案内します。</p>\r\n                     <a class=\"edu-btn\" href=\"/product-lists\">今日あなたの旅を始めましょう！</a>\r\n                  </div>\r\n               </div>\r\n            </div>\r\n         </div>\r\n      </div>\r\n      ; <!-- become-intructor-area-end -->', NULL, NULL),
